parameters.jsonBody:
={{ JSON.stringify({
  to: $json.customer_email,
  template: 'pickup_reminder',
  templateData: {
    customer_name: [($json.first_name || ''), ($json.last_name || '')].filter(Boolean).join(' ') || 'Valued Customer',
    order_number: $json.order_number,
    pickup_location: $json.pickup_location || '',
    pickup_address: $json.pickup_address || '',
    pickup_date: $json.pickup_date ? new Date($json.pickup_date + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' }) : '',
    pickup_time: $json.pickup_time_start && $json.pickup_time_end ? $json.pickup_time_start + ' \u2013 ' + $json.pickup_time_end : ($json.pickup_time_start || ''),
    pickup_instructions: $json.pickup_instructions || 'Please bring a valid ID and your order confirmation.'
  }
}) }}
